fun solve(nums: Array<Long>): Long {
    val n = nums.size
    if (n == 0) return 0L

    // Precompute smallest prime factors (SPF) up to 1e6
    val maxNum = 1000000L
    val spf = sieve(maxNum)

    // Build map from primes to indices where their multiples exist
    val primeToIndices = mutableMapOf<Long, MutableList<Long>>()
    for (i in 0 until n) {
        val x = nums[i]
        if (x == 1L) continue
        val factors = getPrimeFactors(x, spf)
        for (p in factors) {
            primeToIndices.getOrPut(p) { mutableListOf<Long>() }.add(i.toLong())
        }
    }

    // BFS to find minimum steps
    val visited = BooleanArray(n)
    val queue = LinkedList<Pair<Long, Long>>()
    queue.add(Pair(0L, 0L))
    visited[0] = true

    while (queue.isNotEmpty()) {
        val (i, steps) = queue.removeFirst()
        if (i == n - 1L) return steps

        // Check adjacent indices
        for (dir in listOf(-1, 1)) {
            val j = i + dir
            if (j >= 0 && j < n && !visited[j.toInt()]) {
                visited[j.toInt()] = true
                queue.add(Pair(j, steps + 1))
            }
        }

        // Check if current number is a prime and teleport
        val x = nums[i.toInt()]
        if (x > 1 && spf[x.toInt()] == x) {
            val p = x
            val indices = primeToIndices[p] ?: continue
            for (j in indices) {
                if (j != i && !visited[j.toInt()]) {
                    visited[j.toInt()] = true
                    queue.add(Pair(j, steps + 1))
                }
            }
        }
    }

    return -1L
}

fun sieve(max: Long): Array<Long> {
    val spf = Array(max + 1, { 0L })
    for (i in 2..max.toInt()) {
        if (spf[i] == 0L) {
            spf[i] = i.toLong()
            for (j in i * i..max step i) {
                if (spf[j] == 0L) {
                    spf[j] = i.toLong()
                }
            }
        }
    }
    return spf
}

fun getPrimeFactors(x: Long, spf: Array<Long>): Set<Long> {
    val factors = mutableSetOf<Long>()
    if (x == 1L) return factors
    var num = x
    while (num != 1L) {
        val p = spf[num.toInt()]
        factors.add(p)
        while (num % p == 0) {
            num /= p
        }
    }
    return factors
}
